return items.map(item => {
  const c = item.json;
  return {
    json: {
      role: 'Course Lead',
      severity: c.growth_pct > 100 ? 'Critical' : 'High',
      message: `Emerging issue: \"${c.topic_name}\" grew from ${c.last_week_count} to ${c.this_week_count} ` +
               `feedbacks this week (+${c.growth_pct.toFixed(0)}% WoW).`
    }
  };
});

